import React, { useState, useEffect } from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import interactionPlugin from '@fullcalendar/interaction'; 
import axios from 'axios';

const Calendar = () => {
  const [events, setEvents] = useState([]);  // State to store events

  useEffect(() => {
    // Fetch the events from your backend
    axios.get('http://127.0.0.1:3001/events')  // Make sure your backend is running and reachable
      .then(response => {
        console.log(response.data);  // Debug: check if you're getting the events
        setEvents(response.data);    // Set the events to state
      })
      .catch(error => {
        console.error('Error fetching events:', error);  // Debug: check for any errors
      });
  }, []);

  return (
    <FullCalendar
      plugins={[dayGridPlugin, interactionPlugin]}
      initialView="dayGridMonth"
      events={events}  // Pass the events to the calendar
      eventClick={(info) => {
        alert(info.event.title);  // Debugging the click on event
      }}
    />
  );
};

export default Calendar;
